INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cf446b4c-moex-00324', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲已喪妻，有子女乙、丙二人。甲培養乙子赴美留學花費新臺幣（下同）500萬元。丙女結婚時， 甲花費500萬元購買小套房一間贈與丙。甲死亡時留有財產500萬元。甲之遺產分割時，乙可分 得多少遺產？', '["0元", "250萬元", "500萬元", "750萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00325', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲受監護宣告，法院選定其女乙為監護人。乙所為之下列行為，何者應經法院許可？', '["甲被診斷為末期病人，意識昏迷，乙同意不實施維生醫療", "甲罹患長期慢性病，需要醫護服務，乙代理甲與長期照顧機構訂立入住契約", "甲需要醫藥費，活期存款金額不足，乙代理甲將丙銀行之定存解約", "甲所有之A屋過度老舊，乙代理甲將A屋與其基地為對價，與建商丁訂立都更合建契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00326', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲立遺囑將百萬鑽戒遺贈媳婦乙。某日甲之友人丙因應酬需要，向甲商借該鑽戒佩戴。惟該鑽戒 不慎滅失，甲因此氣急攻心而死。甲所為遺贈之效力為何？', '["因遺囑無效，遺贈亦歸於無效", "遺贈視為撤回", "推定以甲對丙之損害賠償請求權為遺贈", "遺贈有效，乙僅得請求丙交付同等價值之鑽戒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00327', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何者具有完全行為能力？', '["現年17歲之甲", "現年18歲之乙", "現年19歲已離婚之丙", "現年20歲受監護宣告之丁 20420 20520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00328', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '15歲之甲未經法定代理人允許，所為下列之法律行為，何者有效？', '["單獨行為", "處分不動產", "日常生活所必需之行為", "設定普通抵押權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00329', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於輔助宣告之敘述，何者錯誤？', '["受輔助宣告人並未喪失行為能力", "受輔助宣告人之財產，應由輔助人管理", "法院得依聲請，指定受輔助宣告人所為之法律行為金額在新臺幣50,000元以上者，須經輔助人 同意", "法院得依聲請，指定受輔助宣告人申辦手機門號及辦理信用卡之法律行為，經輔助人同意方為 有效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00330', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何者非屬不法侵害人格利益之情形？', '["新聞網站未加查證，於明知報導內容不實後，卻拒絕將該報導自系爭網站移除，繼續供他人任 意連結轉載", "於他人居住區域發出超越一般人社會生活所能容忍之噪音", "新聞媒體對於雙方均非公眾人物之私權爭端，揭載足資識別之個人資料", "利用購買人輕率無經驗而使其購買非必要之高價商品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00331', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於短期消滅時效之敘述，何者錯誤？', '["僱傭關係所涉薪資之請求權，因2年間不行使而消滅", "商人、製造人、手工業人所供給之商品及產物之代價，因2年間不行使而消滅", "會計師之報酬及其墊款請求權之行使，因2年間不行使而消滅", "醫師之診費、報酬及其墊款請求權之行使，因2年間不行使而消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00332', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲將1部電動機車出售於乙，乙又將該車贈送並移轉所有權予丙。後來發現甲乃受監護宣告之人， 但乙、丙不知此情事。下列敘述，何者錯誤？', '["甲乃受監護宣告之人，故其所為之債權行為及物權行為皆無效", "乙贈與丙之電動機車，因由受監護宣告之甲處所購得，故乙丙間之贈與契約無效，移轉電動機 車所有權之行為，亦無效", "善意的乙已將電動機車無償讓與丙，故不負返還之責", "善意的丙因善意受讓取得電動機車所有權，其受有利益雖有法律上原因，但基於衡平保護甲之 利益，甲得類推適用民法第183條規定，向丙請求返還電動機車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00333', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '民法第 225 條規定因不可歸責於債務人之事由，致嗣後給付不能之法律效果。下列敘述，何者 錯誤？', '["債務人免給付義務", "債權人得向債務人請求讓與其對第三人之損害賠償請求權", "債權人得向債務人請求交付其因給付不能所受領之賠償物", "債權人得向債務人請求損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
